/* ---- jsPDF loader (CDN) ---- */
function loadJsPDF(){return new Promise((res,rej)=>{if(window.jspdf&&window.jspdf.jsPDF)return res(window.jspdf.jsPDF);const s=document.createElement("script");s.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";s.onload=()=>res(window.jspdf.jsPDF);s.onerror=rej;document.head.appendChild(s);});}

function Brand({size=26}){return(<div style={{display:"flex",alignItems:"center",gap:9}}><div style={{position:"relative",width:size,height:size,display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{position:"absolute",inset:-5,borderRadius:"50%",background:AC,filter:"blur(12px)",opacity:0.45}}/><img src={MARK} alt="" style={{position:"relative",width:size,height:size,objectFit:"contain"}}/></div><div style={{fontSize:size*0.55,fontWeight:800,letterSpacing:0.4,color:TX}}>Sacred<span style={{color:AC}}>Ops</span></div></div>);}
function Sig({i=0}){return(<svg viewBox="0 0 82 32" width="72" height="28"><path d={SIGPATHS[i%4]} fill="none" stroke="#0D0D0D" strokeWidth="2.4" strokeLinecap="round"/></svg>);}
function SigPad({height=84,capRef}){
  const ref=useRef(null);const dr=useRef(false);const lp=useRef(null);const lm=useRef(null);
  const setC=(node)=>{ref.current=node;if(node&&capRef)capRef.current=()=>node.toDataURL("image/png");};
  const xy=(e)=>{const r=ref.current.getBoundingClientRect();const t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*(ref.current.width/r.width),y:(t.clientY-r.top)*(ref.current.height/r.height)};};
  const mid=(a,b)=>({x:(a.x+b.x)/2,y:(a.y+b.y)/2});
  const start=(e)=>{e.preventDefault();dr.current=true;const p=xy(e);lp.current=p;lm.current=p;const c=ref.current.getContext("2d");c.lineJoin="round";c.lineCap="round";c.strokeStyle="#0D0D0D";c.lineWidth=2.5;c.beginPath();c.moveTo(p.x,p.y);};
  const move=(e)=>{if(!dr.current)return;e.preventDefault();const p=xy(e);const m=mid(lp.current,p);const c=ref.current.getContext("2d");c.beginPath();c.moveTo(lm.current.x,lm.current.y);c.quadraticCurveTo(lp.current.x,lp.current.y,m.x,m.y);c.stroke();lp.current=p;lm.current=m;};
  const end=()=>{dr.current=false;};const clear=()=>ref.current.getContext("2d").clearRect(0,0,ref.current.width,ref.current.height);
  return(<div><canvas ref={setC} width={300} height={height} style={{width:"100%",height,background:"#fff",borderRadius:12,border:"1.5px solid "+AC,display:"block",touchAction:"none"}} onMouseDown={start} onMouseMove={move} onMouseUp={end} onMouseLeave={end} onTouchStart={start} onTouchMove={move} onTouchEnd={end}/><button onClick={clear} style={{marginTop:6,background:"none",border:"1px solid "+HL,color:MU,fontSize:10,fontWeight:700,padding:"5px 12px",borderRadius:8,cursor:"pointer",fontFamily:MONO}}>CLEAR</button></div>);
}

/* ---- generic filled-PDF renderer ---- */
async function buildPDF({file,title,meta,sections,sigs},onDone,onErr){
  let jsPDF; try{jsPDF=await loadJsPDF();}catch(e){onErr&&onErr();return;}
  const d=new jsPDF({unit:"pt",format:"letter"});const W=612,M=44;let y=0;
  d.setFillColor(0,59,34);d.rect(0,0,W,58,"F");
  d.setTextColor(255,255,255);d.setFont("helvetica","bold");d.setFontSize(18);d.text("SACRED OPS",M,30);
  d.setFontSize(7);d.setTextColor(180,220,200);d.text("BUILD SAFER  ·  WORK SMARTER",M,44);
  d.setFontSize(8);d.setTextColor(220,235,228);d.text("Generated "+new Date().toLocaleString(),W-M,32,{align:"right"});
  y=84;d.setTextColor(20,20,20);d.setFont("helvetica","bold");d.setFontSize(15);d.text(title,M,y);y+=8;
  d.setDrawColor(4,164,102);d.setLineWidth(2);d.line(M,y,W-M,y);y+=20;
  const ensure=(h)=>{if(y+h>742){d.addPage();y=54;}};
  const kv=(k,v)=>{ensure(16);d.setFont("helvetica","bold");d.setFontSize(9);d.setTextColor(95,95,95);d.text(String(k||""),M,y);d.setFont("helvetica","normal");d.setTextColor(20,20,20);d.setFontSize(10);const ln=d.splitTextToSize(String(v==null||v===""?"—":v),W-M-165);d.text(ln,M+150,y);y+=Math.max(16,ln.length*13);};
  (meta||[]).forEach(m=>kv(m[0],m[1]));
  (sections||[]).forEach(sec=>{
    ensure(32);y+=8;d.setFillColor(24,57,43);d.rect(M,y-11,W-2*M,18,"F");d.setTextColor(255,255,255);d.setFont("helvetica","bold");d.setFontSize(9.5);d.text(sec.h.toUpperCase(),M+8,y+1);y+=22;d.setTextColor(20,20,20);
    (sec.rows||[]).forEach(r=>kv(r[0],r[1]));
    (sec.checks||[]).forEach(c=>{ensure(15);const on=!!c[1];d.setFont("helvetica","bold");d.setFontSize(11);if(on){d.setTextColor(4,164,102);}else{d.setTextColor(150,150,150);}d.text(on?"[x]":"[  ]",M,y);d.setTextColor(20,20,20);d.setFont("helvetica","normal");d.setFontSize(10);const t=d.splitTextToSize(c[0],W-M-46);d.text(t,M+26,y);y+=Math.max(14,t.length*12);});
    (sec.yn||[]).forEach(c=>{ensure(15);d.setFont("helvetica","normal");d.setFontSize(10);d.setTextColor(20,20,20);const t=d.splitTextToSize(c[0],W-M-70);d.text(t,M,y);const v=c[1]||"—";d.setFont("helvetica","bold");if(v==="Y"){d.setTextColor(4,164,102);}else if(v==="N"){d.setTextColor(200,40,40);}else{d.setTextColor(120,120,120);}d.text(v,W-M-24,y,{align:"right"});y+=Math.max(14,t.length*12);});
    (sec.steps||[]).forEach((sp,i)=>{ensure(38);d.setFont("helvetica","bold");d.setFontSize(10);d.setTextColor(4,120,80);const hd=d.splitTextToSize((i+1)+". "+sp.step,W-2*M);d.text(hd,M,y);y+=hd.length*13+2;d.setTextColor(20,20,20);d.setFontSize(9);d.setFont("helvetica","bold");d.text("Hazards:",M,y);d.setFont("helvetica","normal");const hz=d.splitTextToSize(sp.hazard||"\u2014",W-M-58);d.text(hz,M+56,y);y+=Math.max(13,hz.length*12)+1;d.setFont("helvetica","bold");d.text("Controls:",M,y);d.setFont("helvetica","normal");const ct=d.splitTextToSize(sp.control||"\u2014",W-M-58);d.text(ct,M+56,y);y+=Math.max(13,ct.length*12)+1;if(sp.risk){d.setFont("helvetica","bold");d.text("Risk:",M,y);d.setFont("helvetica","normal");d.text(String(sp.risk),M+56,y);y+=13;}d.setDrawColor(228,228,228);d.setLineWidth(0.7);d.line(M,y+1,W-M,y+1);y+=8;});
    if(sec.cols){ensure(24);const cols=sec.cols;const avail=W-2*M;const cw=sec.widths||cols.map(()=>avail/cols.length);d.setFillColor(24,57,43);d.rect(M,y-10,avail,17,"F");d.setTextColor(255,255,255);d.setFont("helvetica","bold");d.setFontSize(8.5);let cx=M+4;cols.forEach((c,i)=>{d.text(String(c),cx,y+1.5);cx+=cw[i];});y+=19;d.setTextColor(20,20,20);(sec.rows||[]).forEach((r,ri)=>{ensure(15);if(ri%2){d.setFillColor(244,247,245);d.rect(M,y-9,avail,14,"F");}let x2=M+4;d.setFont("helvetica",ri===sec.rows.length-1?"bold":"normal");d.setFontSize(8.5);r.forEach((cell,i)=>{const t=d.splitTextToSize(String(cell==null?"":cell),cw[i]-6);d.text(t[0]||"",x2,y);x2+=cw[i];});y+=14;});d.setDrawColor(210,210,210);d.line(M,y-1,W-M,y-1);y+=6;}
    if(sec.text){ensure(18);d.setFont("helvetica","normal");d.setFontSize(10);d.setTextColor(20,20,20);const t=d.splitTextToSize(sec.text,W-2*M);ensure(t.length*12);d.text(t,M,y);y+=t.length*12+4;}
  });
  if(sigs&&sigs.length){y+=12;sigs.forEach(s=>{ensure(78);d.setFont("helvetica","bold");d.setFontSize(9);d.setTextColor(95,95,95);d.text(s.role.toUpperCase(),M,y);y+=4;if(s.img){try{d.addImage(s.img,"PNG",M,y,150,44);}catch(e){}}d.setDrawColor(160,160,160);d.setLineWidth(1);d.line(M,y+48,M+230,y+48);d.line(W-M-150,y+48,W-M,y+48);d.setFont("helvetica","normal");d.setFontSize(9);d.setTextColor(20,20,20);d.text(s.name||"",M,y+60);d.text("Date: "+(s.date||""),W-M-150,y+60);y+=78;});}
  d.save(file);onDone&&onDone();
}

