function Ring({pct,size=56,stroke=5.5,color}){
  const r=(size-stroke)/2,cx=size/2,cy=size/2,circ=2*Math.PI*r,off=circ*(1-Math.min(100,Math.max(0,pct))/100);
  return(<svg width={size} height={size} viewBox={"0 0 "+size+" "+size}>
    <circle cx={cx} cy={cy} r={r} fill="none" stroke="rgba(255,255,255,0.09)" strokeWidth={stroke}/>
    <circle cx={cx} cy={cy} r={r} fill="none" stroke={color} strokeWidth={stroke} strokeDasharray={circ} strokeDashoffset={off} strokeLinecap="round" transform={"rotate(-90 "+cx+" "+cy+")"}/>
    <text x="50%" y="50%" textAnchor="middle" dy="0.32em" fontSize={size*0.24} fontWeight="800" fill={color} fontFamily={SANS}>{pct}%</text>
  </svg>);
}
function greetWord(){const h=new Date().getHours();return h<12?"Good morning":h<17?"Good afternoon":"Good evening";}
function projIcon(div){
  const s=(div||"").toLowerCase();
  if(s.includes("bridge"))return{path:"M2 17h20M4 17V9l4-3 4 3v8M12 17V6l4-3 4 3v11",grad:["#2d4a5e","#12222c"]};
  if(s.includes("marine")||s.includes("underwater"))return{path:"M3 16c1.5 1.5 3 1.5 4.5 0s3-1.5 4.5 0 3 1.5 4.5 0 3-1.5 4.5 0M12 3v9M8 6l4-3 4 3",grad:["#0e5f66","#0a2a30"]};
  if(s.includes("highway")||s.includes("structures"))return{path:"M5 21l4-18h6l4 18M9 13h6M8 17h8",grad:["#5a4a2d","#241d10"]};
  if(s.includes("rail")||s.includes("paving"))return{path:"M4 6h16v11a2 2 0 01-2 2H6a2 2 0 01-2-2zM4 12h16M8 6v13M16 6v13M6 21l-2 2M18 21l2 2",grad:["#4a2d5a","#1d1024"]};
  return{path:"M4 21V9l8-6 8 6v12M9 21v-6h6v6",grad:["#1c3a2c","#0d1d15"]};
}
function Thumb({div,tag,size=64}){
  const ic=projIcon(div);
  return(<div style={{position:"relative",width:size,height:size,borderRadius:14,overflow:"hidden",flexShrink:0,background:"linear-gradient(145deg,"+ic.grad[0]+","+ic.grad[1]+")",border:"1px solid rgba(255,255,255,0.08)"}}>
    <svg viewBox="0 0 24 24" width={size*0.52} height={size*0.52} style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)"}} fill="none" stroke="rgba(255,255,255,0.55)" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"><path d={ic.path}/></svg>
    {tag&&<span style={{position:"absolute",top:4,left:4,fontSize:7,fontWeight:800,letterSpacing:0.3,color:"#fff",background:tag==="GC"?"rgba(4,164,102,0.9)":"rgba(0,0,0,0.65)",padding:"2px 5px",borderRadius:5}}>{tag}</span>}
  </div>);
}
